mapper.select:
SELECT top.cateId AS cateId, top.name AS cateName, SUM(oi.total) AS totalAmount FROM order_item oi JOIN product_variant pv ON oi.prodVariantId = pv.id JOIN product p ON pv.prodNo = p.prodNo JOIN category c ON p.cateId = c.cateId JOIN category top ON top.cateId = COALESCE(c.parentId, c.cateId)
oi.sellerUid = #{sellerUid}
GROUP BY top.cateId, top.name ORDER BY top.cateId ASC
